package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonWriter_value_Test {

  private JsonWriter jsonWriter;
  private StringWriter stringWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void value_null_callsNullValueAndReturnsJsonWriter() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);
    doReturn(spyWriter).when(spyWriter).nullValue();

    JsonWriter returned = spyWriter.value((String) null);

    verify(spyWriter).nullValue();
    assertSame(spyWriter, returned);
  }

  @Test
  public void value_nonNull_callsWriteDeferredNameBeforeValueAndString() throws Exception {
    JsonWriter spyWriter = spy(jsonWriter);

    Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);
    Method beforeValueMethod = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValueMethod.setAccessible(true);
    Method stringMethod = JsonWriter.class.getDeclaredMethod("string", String.class);
    stringMethod.setAccessible(true);

    // Stub private methods via reflection and doAnswer
    doAnswer(invocation -> {
      writeDeferredNameMethod.invoke(spyWriter);
      return null;
    }).when(spyWriter).writeDeferredName();

    doAnswer(invocation -> {
      beforeValueMethod.invoke(spyWriter);
      return null;
    }).when(spyWriter).beforeValue();

    doAnswer(invocation -> {
      stringMethod.invoke(spyWriter, invocation.getArgument(0));
      return null;
    }).when(spyWriter).string(anyString());

    // Instead of trying to stub private methods directly (which is not allowed),
    // we invoke them via reflection inside doAnswer to avoid compilation errors.

    // Call the method under test
    JsonWriter returned = spyWriter.value("testString");

    // Verify private methods invoked via reflection
    // We verify that the private methods were called by spying on the spyWriter's methods
    // but since private methods cannot be verified directly, verify calls on spyWriter will fail.
    // So we verify indirectly by verifying that value("testString") calls string("testString")
    verify(spyWriter).string("testString");

    assertSame(spyWriter, returned);
  }

  @Test
  public void value_emptyString_callsStringWithEmpty() throws Exception {
    JsonWriter spyWriter = spy(jsonWriter);

    Method stringMethod = JsonWriter.class.getDeclaredMethod("string", String.class);
    stringMethod.setAccessible(true);

    doAnswer(invocation -> {
      stringMethod.invoke(spyWriter, invocation.getArgument(0));
      return null;
    }).when(spyWriter).string(anyString());

    JsonWriter returned = spyWriter.value("");

    verify(spyWriter).string("");
    assertSame(spyWriter, returned);
  }

  @Test
  public void value_stringWithSpecialCharacters_callsString() throws Exception {
    JsonWriter spyWriter = spy(jsonWriter);

    Method stringMethod = JsonWriter.class.getDeclaredMethod("string", String.class);
    stringMethod.setAccessible(true);

    doAnswer(invocation -> {
      stringMethod.invoke(spyWriter, invocation.getArgument(0));
      return null;
    }).when(spyWriter).string(anyString());

    String special = "line\nbreak\tand\"quotes\\slash";
    JsonWriter returned = spyWriter.value(special);

    verify(spyWriter).string(special);
    assertSame(spyWriter, returned);
  }
}

